resource "aws_ec2_availability_zone_group" "wlz_bos" {
  group_name    = "us-east-1-wl1-bos-wlz-1"
  opt_in_status = "opted-in"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_ec2_carrier_gateway" "bos" {
  vpc_id = aws_vpc.main.id

  depends_on = [aws_ec2_availability_zone_group.wlz_bos]

  tags = {
    Name = "bos-carrier-gateway"
  }
}

resource "aws_subnet" "wlz_bos" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.200.0/24"
  availability_zone = "us-east-1-wl1-bos-wlz-1"

  tags = {
    Name = "bos-wavelength-subnet"
  }
}

resource "aws_route_table" "wlz_bos" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block         = "0.0.0.0/0"
    carrier_gateway_id = aws_ec2_carrier_gateway.bos.id
  }
}

resource "aws_route_table_association" "wlz_bos" {
  subnet_id      = aws_subnet.wlz_bos.id
  route_table_id = aws_route_table.wlz_bos.id
}

resource "aws_instance" "wlz_app" {
  ami           = data.aws_ami.amazon_linux.id
  instance_type = "t3.medium"
  subnet_id     = aws_subnet.wlz_bos.id

  tags = {
    Name = "bos-5g-edge-server"
  }
}

# Route 53 failover: primary = Wavelength Zone carrier IP, secondary = Region ALB

# Create health check on the WZ carrier IP
HEALTH_CHECK=$(aws route53 create-health-check \
  --caller-reference wlz-hc-$(date +%s) \
  --health-check-config '{
    "IPAddress": "$GAME_IP",
    "Port": 7777,
    "Type": "TCP",
    "RequestInterval": 10,
    "FailureThreshold": 2
  }' \
  --query 'HealthCheck.Id' --output text)

# Primary record: Wavelength Zone carrier IP
aws route53 change-resource-record-sets \
  --hosted-zone-id Z3M3LMPEXAMPLE \
  --change-batch '{
    "Changes": [
      {"Action": "CREATE", "ResourceRecordSet": {
        "Name": "game.example.com", "Type": "A",
        "TTL": 10, "Failover": "PRIMARY",
        "SetIdentifier": "wlz-primary",
        "HealthCheckId": "$HEALTH_CHECK",
        "ResourceRecords": [{"Value": "$GAME_IP"}]
      }}
    ]
  }'
